// Cloudflare Worker — 美股 AI 板块监测
// 部署步骤: dash.cloudflare.com → Workers & Pages → 创建 → 粘贴此代码 → 部署

const HTML = "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>The Ledger — 美股 AI 板块监测</title>\n\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Abril+Fatface&family=Crimson+Text:ital,wght@0,400;0,600;0,700;1,400;1,600&family=Chivo+Mono:wght@300;400;500;600;700&display=swap\" rel=\"stylesheet\">\n\n<style>\n/* ============================================================\n   THE LEDGER — Light Editorial Financial Dashboard\n   ============================================================ */\n:root {\n  --paper:      #f7f4ed;\n  --paper-deep: #efe9dd;\n  --card:       #fdfbf6;\n  --card-hover: #f9f5eb;\n  --ink:        #1a1815;\n  --ink-soft:   #4a4640;\n  --ink-muted:  #8a8578;\n  --ink-faint:  #c4bfb2;\n\n  --ledger-green:  #1f4d3d;\n  --ledger-green-bg: rgba(31,77,61,0.06);\n  --ledger-red:    #8b3a3a;\n  --ledger-red-bg:  rgba(139,58,58,0.05);\n  --navy:          #2c3e5a;\n  --navy-bg:       rgba(44,62,90,0.05);\n  --brass:         #b8935a;\n  --brass-bg:      rgba(184,147,90,0.08);\n\n  --border:        #e0dbd0;\n  --border-strong: #c8c2b4;\n  --border-active: #b8935a;\n\n  --font-display:  'Abril Fatface', 'Times New Roman', serif;\n  --font-serif:    'Crimson Text', 'Times New Roman', serif;\n  --font-mono:     'Chivo Mono', 'SF Mono', 'Courier New', monospace;\n\n  --radius: 2px;\n  --ease: cubic-bezier(0.22, 0.61, 0.36, 1);\n  --ease-slow: cubic-bezier(0.4, 0, 0.2, 1);\n}\n\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml { font-size: 15px; }\n\nbody {\n  background: var(--paper);\n  color: var(--ink);\n  font-family: var(--font-serif);\n  line-height: 1.5;\n  min-height: 100vh;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n  /* Subtle paper fiber texture */\n  background-image:\n    url(\"data:image/svg+xml,%3Csvg width='400' height='400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.03'/%3E%3C/svg%3E\");\n}\n\n/* ============================================================\n   Header — Editorial Masthead\n   ============================================================ */\n.header {\n  position: sticky;\n  top: 0;\n  z-index: 100;\n  background: rgba(247,244,237,0.92);\n  backdrop-filter: blur(12px);\n  -webkit-backdrop-filter: blur(12px);\n  border-bottom: 2px solid var(--ink);\n  padding: 0 32px;\n  height: 68px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n}\n\n.header-masthead {\n  display: flex;\n  align-items: baseline;\n  gap: 16px;\n}\n\n.header-title {\n  font-family: var(--font-display);\n  font-size: 1.8rem;\n  font-weight: 400;\n  color: var(--ink);\n  letter-spacing: 0.02em;\n  line-height: 1;\n}\n\n.header-vol {\n  font-family: var(--font-serif);\n  font-size: 0.62rem;\n  font-style: italic;\n  color: var(--ink-muted);\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.header-divider {\n  width: 1px;\n  height: 20px;\n  background: var(--border-strong);\n}\n\n.header-subtitle {\n  font-family: var(--font-serif);\n  font-size: 0.78rem;\n  font-style: italic;\n  color: var(--ink-soft);\n  letter-spacing: 0.03em;\n}\n\n.header-actions {\n  display: flex;\n  align-items: center;\n  gap: 20px;\n}\n\n/* Ticker — running ink strip */\n.ticker {\n  display: flex;\n  gap: 28px;\n  overflow: hidden;\n  font-family: var(--font-mono);\n  font-size: 0.62rem;\n}\n\n.ticker-item {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  white-space: nowrap;\n}\n\n.ticker-symbol {\n  color: var(--ink-muted);\n  font-weight: 500;\n  letter-spacing: 0.05em;\n}\n\n.ticker-price {\n  color: var(--ink);\n  font-weight: 500;\n}\n\n.ticker-change {\n  font-weight: 600;\n  font-size: 0.6rem;\n}\n\n.ticker-change.up { color: var(--ledger-green); }\n.ticker-change.down { color: var(--ledger-red); }\n\n/* Refresh button — editorial style */\n.btn-refresh {\n  background: transparent;\n  color: var(--ink-soft);\n  border: 1px solid var(--border-strong);\n  padding: 6px 18px;\n  font-family: var(--font-mono);\n  font-size: 0.6rem;\n  letter-spacing: 0.08em;\n  cursor: pointer;\n  transition: all 0.2s var(--ease-slow);\n  text-transform: uppercase;\n}\n\n.btn-refresh:hover {\n  color: var(--ink);\n  border-color: var(--ink);\n  background: rgba(26,24,21,0.04);\n}\n\n.btn-refresh:active { transform: scale(0.97); }\n.btn-refresh.loading { opacity: 0.4; pointer-events: none; }\n\n.meta-time {\n  font-family: var(--font-mono);\n  font-size: 0.58rem;\n  color: var(--ink-muted);\n  letter-spacing: 0.06em;\n}\n\n/* Mode badge */\n.mode-badge {\n  font-family: var(--font-mono);\n  font-size: 0.5rem;\n  letter-spacing: 0.12em;\n  padding: 2px 8px;\n  text-transform: uppercase;\n  font-weight: 500;\n  border: 1px solid;\n}\n\n.mode-badge.mock { color: var(--ink-muted); border-color: var(--ink-faint); }\n.mode-badge.live { color: var(--ledger-green); border-color: rgba(31,77,61,0.3); }\n\n/* ============================================================\n   Main Layout — Ledger Grid\n   ============================================================ */\n.main-grid {\n  position: relative;\n  z-index: 1;\n  display: grid;\n  grid-template-columns: 1fr 1fr 250px;\n  max-width: 1480px;\n  margin: 32px auto 0;\n  padding: 0 32px;\n  gap: 20px;\n}\n\n.sector-chip  { grid-column: 1; grid-row: 1; }\n.sector-cloud { grid-column: 2; grid-row: 1; }\n.sector-app   { grid-column: 1; grid-row: 2; }\n.sector-cyber { grid-column: 2; grid-row: 2; }\n.side-panel   { grid-column: 3; grid-row: 1 / 3; }\n.kline-full   { grid-column: 1 / 4; grid-row: 3; }\n\n/* ============================================================\n   Sector Panel — Ledger Page\n   ============================================================ */\n.sector-panel {\n  background: var(--card);\n  border: 1px solid var(--border);\n  transition: all 0.3s var(--ease-slow);\n}\n\n.sector-panel:hover { border-color: var(--border-strong); }\n\n.sector-head {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 18px 20px;\n  cursor: pointer;\n  user-select: none;\n  border-bottom: 1px solid var(--border);\n  transition: border-color 0.2s;\n}\n\n.sector-head:hover { border-color: var(--border-strong); }\n\n.sector-label-group {\n  display: flex;\n  align-items: baseline;\n  gap: 10px;\n}\n\n.sector-numeral {\n  font-family: var(--font-display);\n  font-size: 1rem;\n  color: var(--ink-muted);\n  line-height: 1;\n}\n\n.sector-title {\n  font-family: var(--font-serif);\n  font-size: 1.05rem;\n  font-weight: 600;\n  font-style: italic;\n  color: var(--ink);\n  letter-spacing: 0.02em;\n}\n\n.sector-tag {\n  font-family: var(--font-mono);\n  font-size: 0.5rem;\n  color: var(--ink-muted);\n  letter-spacing: 0.1em;\n  text-transform: uppercase;\n}\n\n.sector-head-right {\n  display: flex;\n  align-items: center;\n  gap: 14px;\n}\n\n.sector-pct {\n  font-family: var(--font-mono);\n  font-weight: 600;\n  font-size: 0.85rem;\n}\n\n.sector-pct.up { color: var(--ledger-green); }\n.sector-pct.down { color: var(--ledger-red); }\n\n.sector-carat {\n  font-size: 0.5rem;\n  color: var(--ink-muted);\n  transition: transform 0.35s var(--ease);\n}\n\n.sector-panel.folded .sector-carat { transform: rotate(-90deg); }\n\n.sector-body {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  transition: all 0.35s var(--ease);\n  overflow: hidden;\n}\n\n.sector-panel.folded .sector-body { max-height: 0 !important; opacity: 0; }\n\n/* Vertical rules between cards */\n.sector-body > * + * { border-left: 1px solid var(--border); }\n\n/* ============================================================\n   Stock Card — The Ticker Entry\n   ============================================================ */\n.stock-card {\n  padding: 20px 16px;\n  cursor: pointer;\n  transition: all 0.25s var(--ease-slow);\n  position: relative;\n  animation: entryFade 0.55s var(--ease) both;\n}\n\n.stock-card:nth-child(1) { animation-delay: 0.04s; }\n.stock-card:nth-child(2) { animation-delay: 0.1s; }\n.stock-card:nth-child(3) { animation-delay: 0.16s; }\n.stock-card:nth-child(4) { animation-delay: 0.22s; }\n\n@keyframes entryFade {\n  from { opacity: 0; transform: translateY(6px); }\n  to   { opacity: 1; transform: translateY(0); }\n}\n\n.stock-card:hover { background: var(--card-hover); }\n\n.stock-card.selected {\n  background: var(--brass-bg);\n}\n\n.stock-card.selected::after {\n  content: '';\n  position: absolute;\n  left: 0; top: 0; bottom: 0;\n  width: 3px;\n  background: var(--brass);\n}\n\n.stock-symbol {\n  font-family: var(--font-mono);\n  font-weight: 600;\n  font-size: 0.82rem;\n  color: var(--ink);\n  letter-spacing: 0.04em;\n  margin-bottom: 2px;\n}\n\n.stock-name {\n  font-family: var(--font-serif);\n  font-size: 0.68rem;\n  color: var(--ink-soft);\n  font-style: italic;\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  margin-bottom: 10px;\n}\n\n.stock-price-row {\n  display: flex;\n  align-items: baseline;\n  gap: 6px;\n  margin-bottom: 4px;\n}\n\n.stock-price {\n  font-family: var(--font-mono);\n  font-size: 1.35rem;\n  font-weight: 500;\n  color: var(--ink);\n  letter-spacing: -0.02em;\n}\n\n.stock-change {\n  font-family: var(--font-mono);\n  font-size: 0.75rem;\n  font-weight: 600;\n}\n\n.stock-change.up { color: var(--ledger-green); }\n.stock-change.down { color: var(--ledger-red); }\n\n.stock-vol-row {\n  display: flex;\n  align-items: baseline;\n  gap: 6px;\n  margin-top: 8px;\n  font-family: var(--font-mono);\n  font-size: 0.58rem;\n  color: var(--ink-muted);\n  letter-spacing: 0.04em;\n}\n\n.stock-vol-num { white-space: nowrap; }\n\n.stock-vol-rule {\n  flex: 1;\n  height: 3px;\n  background: var(--border);\n}\n\n.stock-vol-fill {\n  height: 100%;\n  transition: width 0.8s var(--ease), background 0.3s var(--ease-slow);\n}\n\n.stock-vol-fill.inflow  { background: rgba(31,77,61,0.45); }\n.stock-vol-fill.outflow { background: rgba(139,58,58,0.35); }\n.stock-card.selected .stock-vol-fill.inflow  { background: var(--ledger-green); }\n.stock-card.selected .stock-vol-fill.outflow { background: var(--ledger-red); }\n\n/* ============================================================\n   Side Panel — Market Ranking\n   ============================================================ */\n.side-panel {\n  background: var(--card);\n  border: 1px solid var(--border);\n  padding: 20px;\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.side-heading {\n  font-family: var(--font-serif);\n  font-size: 1rem;\n  font-weight: 600;\n  font-style: italic;\n  color: var(--ink);\n  padding-bottom: 10px;\n  border-bottom: 1px solid var(--border);\n  letter-spacing: 0.02em;\n}\n\n.rank-list { display: flex; flex-direction: column; gap: 3px; }\n\n.rank-item {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 13px 14px;\n  transition: background 0.2s var(--ease-slow);\n}\n\n.rank-item:hover { background: var(--card-hover); }\n\n.rank-num {\n  font-family: var(--font-display);\n  font-size: 1.5rem;\n  color: var(--ink-faint);\n  width: 24px;\n  line-height: 1;\n}\n\n.rank-label {\n  font-family: var(--font-serif);\n  font-size: 0.85rem;\n  font-weight: 500;\n  font-style: italic;\n  color: var(--ink);\n}\n\n.rank-stats { text-align: right; }\n\n.rank-pct {\n  font-family: var(--font-mono);\n  font-weight: 600;\n  font-size: 0.9rem;\n}\n\n.rank-pct.up { color: var(--ledger-green); }\n.rank-pct.down { color: var(--ledger-red); }\n\n.rank-tally {\n  font-family: var(--font-mono);\n  font-size: 0.56rem;\n  color: var(--ink-muted);\n  margin-top: 2px;\n}\n\n.rank-tally .t-up { color: var(--ledger-green); }\n.rank-tally .t-down { color: var(--ledger-red); }\n\n/* Pipeline teaser */\n.pipeline {\n  margin-top: auto;\n  padding-top: 14px;\n  border-top: 1px solid var(--border);\n}\n\n.pipeline-label {\n  font-family: var(--font-mono);\n  font-size: 0.5rem;\n  color: var(--ink-faint);\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  margin-bottom: 10px;\n}\n\n.pipeline-item {\n  display: block;\n  font-family: var(--font-serif);\n  font-size: 0.7rem;\n  font-style: italic;\n  color: var(--ink-faint);\n  padding: 4px 0;\n  transition: color 0.2s;\n  text-decoration: none;\n}\n\n.pipeline-item:hover { color: var(--ink-muted); }\n\n/* ============================================================\n   K-line Section — The Chart\n   ============================================================ */\n.kline-full {\n  background: var(--card);\n  border: 1px solid var(--border);\n  padding: 20px;\n}\n\n.kline-top {\n  display: flex;\n  align-items: baseline;\n  justify-content: space-between;\n  margin-bottom: 14px;\n}\n\n.kline-top-left {\n  display: flex;\n  align-items: baseline;\n  gap: 14px;\n}\n\n.kline-heading {\n  font-family: var(--font-serif);\n  font-size: 1rem;\n  font-weight: 600;\n  font-style: italic;\n  color: var(--ink);\n  letter-spacing: 0.02em;\n}\n\n.kline-ticker {\n  font-family: var(--font-mono);\n  font-size: 0.78rem;\n  font-weight: 600;\n  color: var(--navy);\n  letter-spacing: 0.05em;\n}\n\n.kline-summary {\n  display: none;\n  font-family: var(--font-mono);\n  font-size: 0.62rem;\n  color: var(--ink-soft);\n  letter-spacing: 0.04em;\n  margin-bottom: 12px;\n  padding: 10px 14px;\n  background: var(--card-hover);\n  border: 1px solid var(--border);\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px 18px;\n}\n\n.kline-summary span { white-space: nowrap; }\n.kline-summary .ks-label { color: var(--ink-muted); }\n.kline-summary .ks-up { color: var(--ledger-green); font-weight: 600; }\n.kline-summary .ks-down { color: var(--ledger-red); font-weight: 600; }\n\n/* ============================================================\n   News Feed\n   ============================================================ */\n.news-section {\n  position: relative;\n  z-index: 1;\n  max-width: 1480px;\n  margin: 20px auto 0;\n  padding: 0 32px;\n}\n\n.news-panel {\n  background: var(--card);\n  border: 1px solid var(--border);\n  padding: 18px 20px;\n}\n\n.news-head {\n  font-family: var(--font-serif);\n  font-size: 0.9rem;\n  font-weight: 600;\n  font-style: italic;\n  color: var(--ink);\n  margin-bottom: 10px;\n  letter-spacing: 0.02em;\n}\n\n.news-list { display: flex; flex-direction: column; gap: 2px; }\n\n.news-item {\n  display: flex;\n  align-items: baseline;\n  gap: 12px;\n  padding: 6px 0;\n  font-family: var(--font-serif);\n  font-size: 0.78rem;\n  color: var(--ink-soft);\n  font-style: italic;\n  transition: color 0.2s;\n  text-decoration: none;\n  border-bottom: 1px dotted var(--border);\n}\n\n.news-item:hover { color: var(--ink); }\n\n.news-sentiment {\n  font-family: var(--font-mono);\n  font-size: 0.55rem;\n  font-weight: 600;\n  padding: 1px 6px;\n  letter-spacing: 0.06em;\n  white-space: nowrap;\n  text-transform: uppercase;\n  font-style: normal;\n}\n\n.news-sentiment.bullish { color: var(--ledger-green); border: 1px solid rgba(31,77,61,0.3); }\n.news-sentiment.bearish { color: var(--ledger-red); border: 1px solid rgba(139,58,58,0.3); }\n.news-sentiment.neutral { color: var(--ink-muted); border: 1px solid var(--border-strong); }\n\n.news-time {\n  font-family: var(--font-mono);\n  font-size: 0.55rem;\n  color: var(--ink-muted);\n  white-space: nowrap;\n  font-style: normal;\n}\n\n.kline-range-btns { display: flex; gap: 2px; }\n\n.kline-rbtn {\n  background: transparent;\n  color: var(--ink-muted);\n  border: 1px solid var(--border);\n  padding: 4px 12px;\n  cursor: pointer;\n  font-family: var(--font-mono);\n  font-size: 0.58rem;\n  letter-spacing: 0.06em;\n  transition: all 0.2s var(--ease-slow);\n}\n\n.kline-rbtn:hover { color: var(--ink-soft); border-color: var(--border-strong); }\n\n.kline-rbtn.active {\n  color: var(--navy);\n  border-color: rgba(44,62,90,0.4);\n  background: var(--navy-bg);\n}\n\n.kline-empty {\n  text-align: center;\n  padding: 56px 20px;\n  font-family: var(--font-serif);\n  font-size: 0.95rem;\n  font-style: italic;\n  color: var(--ink-faint);\n}\n\ncanvas#klineCanvas { display: block; width: 100%; }\n\n/* ============================================================\n   Footer — Colophon\n   ============================================================ */\n.footer {\n  position: relative;\n  z-index: 1;\n  max-width: 1480px;\n  margin: 0 auto;\n  padding: 18px 32px 32px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  font-family: var(--font-mono);\n  font-size: 0.55rem;\n  color: var(--ink-muted);\n  letter-spacing: 0.06em;\n}\n\n.footer-group { display: flex; align-items: center; gap: 14px; }\n\n.footer-sep { color: var(--border-strong); }\n\n.footer-mark {\n  display: inline-block;\n  width: 6px; height: 6px;\n}\n\n.footer-mark.up { background: var(--ledger-green); }\n.footer-mark.down { background: var(--ledger-red); }\n\n/* ============================================================\n   Toast\n   ============================================================ */\n.toast {\n  position: fixed;\n  bottom: 36px;\n  left: 50%;\n  transform: translateX(-50%);\n  background: var(--card);\n  color: var(--ink);\n  border: 1px solid var(--border-strong);\n  padding: 10px 24px;\n  font-family: var(--font-mono);\n  font-size: 0.65rem;\n  letter-spacing: 0.06em;\n  opacity: 0;\n  transition: opacity 0.4s;\n  pointer-events: none;\n  z-index: 1000;\n}\n\n.toast.show { opacity: 1; }\n\n/* ============================================================\n   Responsive\n   ============================================================ */\n@media (max-width: 1100px) {\n  .main-grid {\n    grid-template-columns: 1fr 1fr;\n    padding: 0 16px;\n    gap: 12px;\n    margin-top: 20px;\n  }\n  .sector-chip  { grid-column: 1; grid-row: auto; }\n  .sector-cloud { grid-column: 2; grid-row: auto; }\n  .sector-app   { grid-column: 1; grid-row: auto; }\n  .sector-cyber { grid-column: 2; grid-row: auto; }\n  .side-panel   { grid-column: 1 / 3; grid-row: auto; }\n  .kline-full   { grid-column: 1 / 3; grid-row: auto; }\n  .sector-body   { grid-template-columns: repeat(2, 1fr); }\n  .ticker        { display: none; }\n}\n\n@media (max-width: 640px) {\n  .header        { padding: 0 12px; height: 52px; }\n  .header-title  { font-size: 1.2rem; }\n  .header-subtitle { display: none; }\n  .header-divider { display: none; }\n  .main-grid     { grid-template-columns: 1fr; padding: 0 8px; gap: 8px; margin-top: 12px; }\n  .sector-chip, .sector-cloud, .sector-app, .sector-cyber,\n  .side-panel, .kline-full { grid-column: 1; }\n  .sector-body   { grid-template-columns: repeat(2, 1fr); }\n  .stock-card    { padding: 14px 12px; }\n  .stock-price   { font-size: 1.1rem; }\n  .btn-refresh span { display: none; }\n}\n</style>\n</head>\n<body>\n\n<!-- ============================================================\n     Header — Masthead\n     ============================================================ -->\n<header class=\"header\">\n  <div class=\"header-masthead\">\n    <span class=\"header-title\">The Ledger</span>\n    <span class=\"header-divider\"></span>\n    <span class=\"header-vol\">Vol. I</span>\n    <span class=\"header-subtitle\">美股 AI 板块监测</span>\n    <span class=\"mode-badge mock\" id=\"modeBadge\">mock</span>\n  </div>\n\n  <div class=\"ticker\" id=\"tickerStrip\"></div>\n\n  <div class=\"header-actions\">\n    <span class=\"meta-time\" id=\"statusMsg\">Ready — click Refresh</span>\n    <span class=\"meta-time\" id=\"lastUpdate\">--:--:--</span>\n    <button class=\"btn-refresh\" id=\"btnRefresh\" onclick=\"handleRefresh()\">\n      ↻ <span>Refresh</span>\n    </button>\n  </div>\n</header>\n\n<!-- ============================================================\n     Main Grid\n     ============================================================ -->\n<!-- Debug Console -->\n<div style=\"max-width:1480px;margin:16px auto 0;padding:0 32px;\" id=\"debugPanel\">\n  <div style=\"background:var(--card);border:1px solid var(--border);padding:10px 16px;font-family:var(--font-mono);font-size:0.62rem;color:var(--ink-muted);letter-spacing:0.04em;\" id=\"debugMsg\">\n    ⏳ Initializing…\n  </div>\n</div>\n\n<div class=\"main-grid\">\n\n  <!-- Sector I: Chips -->\n  <div class=\"sector-panel sector-chip\" id=\"sector-chip\">\n    <div class=\"sector-head\" onclick=\"toggleSector('chip')\">\n      <div class=\"sector-label-group\">\n        <span class=\"sector-numeral\">I.</span>\n        <span class=\"sector-title\">AI Chips &amp; Semiconductors</span>\n        <span class=\"sector-tag\">算力底层</span>\n      </div>\n      <div class=\"sector-head-right\">\n        <span class=\"sector-pct\" id=\"avg-chip\">—</span>\n        <span class=\"sector-carat\">▾</span>\n      </div>\n    </div>\n    <div class=\"sector-body\" id=\"body-chip\"></div>\n  </div>\n\n  <!-- Sector II: Cloud -->\n  <div class=\"sector-panel sector-cloud\" id=\"sector-cloud\">\n    <div class=\"sector-head\" onclick=\"toggleSector('cloud')\">\n      <div class=\"sector-label-group\">\n        <span class=\"sector-numeral\">II.</span>\n        <span class=\"sector-title\">Cloud Infrastructure</span>\n        <span class=\"sector-tag\">训练推理平台</span>\n      </div>\n      <div class=\"sector-head-right\">\n        <span class=\"sector-pct\" id=\"avg-cloud\">—</span>\n        <span class=\"sector-carat\">▾</span>\n      </div>\n    </div>\n    <div class=\"sector-body\" id=\"body-cloud\"></div>\n  </div>\n\n  <!-- Sector III: Apps -->\n  <div class=\"sector-panel sector-app\" id=\"sector-app\">\n    <div class=\"sector-head\" onclick=\"toggleSector('app')\">\n      <div class=\"sector-label-group\">\n        <span class=\"sector-numeral\">III.</span>\n        <span class=\"sector-title\">AI Enterprise Software</span>\n        <span class=\"sector-tag\">企业AI产品</span>\n      </div>\n      <div class=\"sector-head-right\">\n        <span class=\"sector-pct\" id=\"avg-app\">—</span>\n        <span class=\"sector-carat\">▾</span>\n      </div>\n    </div>\n    <div class=\"sector-body\" id=\"body-app\"></div>\n  </div>\n\n  <!-- Sector IV: Cybersecurity -->\n  <div class=\"sector-panel sector-cyber\" id=\"sector-cyber\">\n    <div class=\"sector-head\" onclick=\"toggleSector('cyber')\">\n      <div class=\"sector-label-group\">\n        <span class=\"sector-numeral\">IV.</span>\n        <span class=\"sector-title\">AI Cybersecurity</span>\n        <span class=\"sector-tag\">AI安全攻防</span>\n      </div>\n      <div class=\"sector-head-right\">\n        <span class=\"sector-pct\" id=\"avg-cyber\">—</span>\n        <span class=\"sector-carat\">▾</span>\n      </div>\n    </div>\n    <div class=\"sector-body\" id=\"body-cyber\"></div>\n  </div>\n\n  <!-- Side Panel -->\n  <aside class=\"side-panel\" id=\"comparison\">\n    <div class=\"side-heading\">Sector Ranking</div>\n    <div class=\"rank-list\" id=\"compList\"></div>\n    <div class=\"pipeline\">\n      <div class=\"pipeline-label\">Expansion Pipeline</div>\n      <span class=\"pipeline-item\">V. Foundation Models — pending</span>\n      <span class=\"pipeline-item\">VI. Data &amp; Analytics — pending</span>\n      <span class=\"pipeline-item\">VII. Robotics &amp; Autonomy — pending</span>\n      <span class=\"pipeline-item\">VIII. Fintech &amp; Consumer AI — pending</span>\n    </div>\n  </aside>\n\n  <!-- K-line -->\n  <section class=\"kline-full\" id=\"klineSection\">\n    <div class=\"kline-top\">\n      <div class=\"kline-top-left\">\n        <span class=\"kline-heading\">Daily Price Chart</span>\n        <span class=\"kline-ticker\" id=\"klineStockLabel\">select a ticker</span>\n      </div>\n      <div class=\"kline-range-btns\">\n        <button class=\"kline-rbtn active\" onclick=\"setKlineRange(30, this)\">30D</button>\n        <button class=\"kline-rbtn\" onclick=\"setKlineRange(60, this)\">60D</button>\n        <button class=\"kline-rbtn\" onclick=\"setKlineRange(90, this)\">90D</button>\n      </div>\n    </div>\n    <div class=\"kline-summary\" id=\"klineSummary\" style=\"display:none;\"></div>\n    <div id=\"klinePlaceholder\">\n      <div class=\"kline-empty\">↑ select a ticker above to render daily candlestick chart</div>\n    </div>\n    <canvas id=\"klineCanvas\" style=\"display:none;\"></canvas>\n  </section>\n\n</div>\n\n<!-- News Feed -->\n<div class=\"news-section\">\n  <div class=\"news-panel\">\n    <div class=\"news-head\">Market Intelligence — AI Sector News &amp; Sentiment</div>\n    <div class=\"news-list\" id=\"newsList\">\n      <div class=\"news-item\" style=\"color:var(--ink-muted);font-style:italic;\">Loading news feed…</div>\n    </div>\n  </div>\n</div>\n\n<!-- Footer -->\n<div class=\"footer\">\n  <div class=\"footer-group\">\n    <span id=\"apiCount\">calls: —</span>\n    <span class=\"footer-sep\">|</span>\n    <span><span class=\"footer-mark up\"></span> gain</span>\n    <span><span class=\"footer-mark down\"></span> loss</span>\n  </div>\n  <span id=\"footerTime\">—</span>\n</div>\n\n<!-- Toast -->\n<div class=\"toast\" id=\"toast\"></div>\n\n<!-- ============================================================\n     JavaScript — Core Logic (unchanged data layer)\n     ============================================================ -->\n<script>\n'use strict';\n\n// 自动检测：本地代理 → 真实数据 | 直接打开文件 → Mock\nconst ON_LOCAL_PROXY = window.location.port==='8765' || window.location.hostname==='localhost';\nconst USE_MOCK = !ON_LOCAL_PROXY; // 代理启动时用真实数据\nconst PROXY_URL = ON_LOCAL_PROXY ? '/api/stock' : 'http://localhost:8765/api/stock';\nconst NEWS_URL = ON_LOCAL_PROXY ? '/api/news' : 'http://localhost:8765/api/news';\nconst CACHE_KEY = 'ai_dashboard_yf_v1';\n\nconst CACHE_TTL = { quote: 5*60*1000, daily: 30*60*1000 };\n\nconst SECTORS = {\n  chip: { id:'chip', numeral:'I.', name:'AI Chips & Semiconductors', tag:'算力底层', stocks:[\n    {symbol:'NVDA',name:'NVIDIA Corporation',basePrice:140},\n    {symbol:'AMD',name:'Advanced Micro Devices',basePrice:160},\n    {symbol:'AVGO',name:'Broadcom Inc.',basePrice:185},\n    {symbol:'TSM',name:'Taiwan Semiconductor',basePrice:175}\n  ]},\n  cloud: { id:'cloud', numeral:'II.', name:'Cloud Infrastructure', tag:'训练推理平台', stocks:[\n    {symbol:'MSFT',name:'Microsoft Corporation',basePrice:465},\n    {symbol:'AMZN',name:'Amazon.com, Inc.',basePrice:225},\n    {symbol:'GOOGL',name:'Alphabet Inc.',basePrice:195},\n    {symbol:'ORCL',name:'Oracle Corporation',basePrice:185}\n  ]},\n  app: { id:'app', numeral:'III.', name:'AI Enterprise Software', tag:'企业AI产品', stocks:[\n    {symbol:'CRM',name:'Salesforce, Inc.',basePrice:305},\n    {symbol:'PLTR',name:'Palantir Technologies',basePrice:105},\n    {symbol:'SNOW',name:'Snowflake Inc.',basePrice:170},\n    {symbol:'CRWD',name:'CrowdStrike Holdings',basePrice:385}\n  ]},\n  cyber: { id:'cyber', numeral:'IV.', name:'AI Cybersecurity', tag:'AI安全攻防', stocks:[\n    {symbol:'PANW',name:'Palo Alto Networks',basePrice:375},\n    {symbol:'ZS',name:'Zscaler, Inc.',basePrice:200},\n    {symbol:'NET',name:'Cloudflare, Inc.',basePrice:130},\n    {symbol:'S',name:'SentinelOne, Inc.',basePrice:28}\n  ]}\n};\n\n/*\n * Reserved: foundation, data, cyber, robotics, fintech\n * (see previous version for full definitions)\n */\n\nlet stockData = {}, selectedStock = null, klineRange = 30, apiCallCount = 0, lastRefreshTime = null;\n\n// =================== Debug ===================\nconst debugLines=[];\nfunction debugLog(msg){\n  debugLines.push(new Date().toLocaleTimeString()+' '+msg);\n  if(debugLines.length>20)debugLines.shift();\n  const el=document.getElementById('debugMsg');\n  if(el)el.innerHTML=debugLines.map(l=>'▸ '+l).join('<br>');\n  console.log('[debug]',msg);\n}\n\n// =================== Mock Data ===================\nfunction generateMockDaily(sym, base, days=120) {\n  const data=[], vol=base*0.025;\n  let p=base, d=new Date(); d.setDate(d.getDate()-Math.floor(days*1.4));\n  while(data.length<days){d.setDate(d.getDate()+1);if(d.getDay()===0||d.getDay()===6)continue;\n    const ch=(Math.random()-0.48)*vol, o=p, c=p+ch;\n    data.push({date:d.toISOString().split('T')[0],open:+o.toFixed(2),high:+(Math.max(o,c)+Math.random()*vol*.6).toFixed(2),low:+(Math.min(o,c)-Math.random()*vol*.6).toFixed(2),close:+c.toFixed(2),volume:Math.floor(1e6+Math.random()*8e6*(base/100))});\n    p=c;\n  }return data;\n}\n\nfunction loadMockData(){\n  const all={};\n  for(const sec of Object.values(SECTORS))for(const st of sec.stocks){\n    const daily=generateMockDaily(st.symbol,st.basePrice,120);\n    const last=daily[daily.length-1],prev=daily[daily.length-2]||last;\n    all[st.symbol]={quote:{symbol:st.symbol,price:last.close,change:+(last.close-prev.close).toFixed(2),changePercent:+(((last.close-prev.close)/prev.close)*100).toFixed(2),volume:last.volume,prevClose:prev.close},daily};\n  }stockData=all;\n}\n\n// =================== API — Yahoo Finance ===================\n// 一次请求同时返回 Quote + 日线 OHLCV，无需 API Key\nasync function fetchYF(symbol){\n  if(USE_MOCK)return null;\n  apiCallCount++;\n  const url=PROXY_URL?`${PROXY_URL}?symbol=${symbol}`:`https://query1.finance.yahoo.com/v8/finance/chart/${symbol}?range=3mo&interval=1d`;\n  try{\n    const r=await fetch(url);\n    if(!r.ok){debugLog('HTTP '+r.status+' for '+symbol);return null;}\n    const j=await r.json();\n    return j;\n  }catch(e){debugLog('NETWORK ERROR '+symbol+': '+e.message);return null;}\n}\n\nfunction parseYF(j){\n  // 解析 Yahoo Finance v8 chart API 响应\n  if(!j||!j.chart||!j.chart.result||!j.chart.result.length)return null;\n  const r=j.chart.result[0];\n  const meta=r.meta;\n  if(!meta)return null;\n\n  // Quote\n  const price=meta.regularMarketPrice;\n  const prevClose=meta.chartPreviousClose||meta.previousClose||price;\n  if(price==null){console.warn('parseYF: null price for',meta.symbol);return null;}\n  const change=+(price-prevClose).toFixed(2);\n  const changePercent=prevClose?+((change/prevClose)*100).toFixed(2):0;\n  const quote={\n    symbol:meta.symbol,\n    price:price,\n    change:change,\n    changePercent:changePercent,\n    volume:meta.regularMarketVolume||0,\n    prevClose:prevClose,\n    high52w:meta.fiftyTwoWeekHigh,\n    low52w:meta.fiftyTwoWeekLow,\n  };\n\n  // Daily OHLCV\n  const timestamps=r.timestamp||[];\n  const indicators=r.indicators&&r.indicators.quote&&r.indicators.quote[0];\n  const daily=[];\n  if(timestamps.length&&indicators){\n    for(let i=0;i<timestamps.length;i++){\n      // 跳过任何 OHLC 为空的数据点（当日未收盘等）\n      const o=indicators.open[i],h=indicators.high[i],l=indicators.low[i],c=indicators.close[i];\n      if(o==null||h==null||l==null||c==null)continue;\n      daily.push({\n        date:new Date(timestamps[i]*1000).toISOString().split('T')[0],\n        open:+o.toFixed(2),\n        high:+h.toFixed(2),\n        low:+l.toFixed(2),\n        close:+c.toFixed(2),\n        volume:indicators.volume[i]||0,\n      });\n    }\n  }\n\n  return {quote,daily};\n}\n\nasync function fetchAll(force=false){\n  if(USE_MOCK){loadMockData();return;}\n\n  const cached=loadCache();\n  if(cached&&!force&&(Date.now()-cached.timestamp<CACHE_TTL.quote)){\n    stockData=cached.data;lastRefreshTime=new Date(cached.timestamp);return;\n  }\n\n  const allStocks=[];\n  for(const sec of Object.values(SECTORS))for(const st of sec.stocks)allStocks.push(st);\n  const total=allStocks.length;\n  debugLog('fetchAll: '+total+' stocks to load');\n\n  // 收集数据\n  const fresh={};\n  let failCount=0;\n\n  for(let i=0;i<allStocks.length;i++){\n    const st=allStocks[i];\n    updateLoadProgress(i, allStocks.length, st.symbol);\n\n    try{\n      const j=await fetchYF(st.symbol);\n      const parsed=parseYF(j);\n      if(parsed&&parsed.quote){\n        fresh[st.symbol]=parsed;\n        debugLog('OK '+st.symbol+' $'+parsed.quote.price);\n      } else {\n        failCount++;\n        debugLog('FAIL '+st.symbol+' (no data)');\n      }\n    }catch(e){\n      failCount++;\n      debugLog('ERROR '+st.symbol+': '+e.message);\n    }\n\n    // 渐进渲染\n    stockData={...stockData,...fresh};\n    renderAll();\n\n    if(i<allStocks.length-1)await sleep(500);\n  }\n\n  console.log('fetchAll done:',Object.keys(fresh).length,'/',total,'loaded,',failCount,'failed');\n  if(Object.keys(fresh).length){\n    saveCache(stockData);\n    lastRefreshTime=new Date();\n  } else if(failCount===total){\n    showToast('All requests failed — check network');\n  }\n  clearLoadProgress();\n}\n\n// 加载进度提示\nfunction updateLoadProgress(i, total, symbol){\n  const btn=document.getElementById('btnRefresh');\n  if(btn)btn.innerHTML=`↻ <span>${i+1}/${total} ${symbol}</span>`;\n  const st=document.getElementById('statusMsg');\n  if(st)st.textContent=`Loading ${i+1}/${total} — ${symbol}`;\n}\n\nfunction clearLoadProgress(){\n  const btn=document.getElementById('btnRefresh');\n  if(btn)btn.innerHTML='↻ <span>Refresh</span>';\n  const st=document.getElementById('statusMsg');\n  if(st){\n    const n=Object.keys(stockData).length;\n    st.textContent=n?`Loaded ${n} tickers`:'Ready — click Refresh';\n  }\n}\n\n// =================== Cache ===================\nfunction saveCache(d){try{localStorage.setItem(CACHE_KEY,JSON.stringify({timestamp:Date.now(),data:d}));}catch(e){}}\nfunction loadCache(){try{const r=localStorage.getItem(CACHE_KEY);return r?JSON.parse(r):null;}catch(e){return null;}}\n\n// =================== Render ===================\nfunction renderAll(){renderTicker();renderSectors();renderComparison();renderNews();if(selectedStock)renderKline(selectedStock);updateMeta();}\nlet newsCache=[];\n\nfunction renderNews(){\n  const list=document.getElementById('newsList');\n  if(!list)return;\n  if(!newsCache.length){\n    list.innerHTML=`<div class=\"news-item\" style=\"color:var(--ink-muted);font-style:italic;\">Loading news…</div>`;\n    return;\n  }\n  list.innerHTML=newsCache.slice(0,10).map(n=>{\n    const s=(n.sentiment||n.overall_sentiment_label||'neutral').toLowerCase();\n    const cls=s==='bullish'?'bullish':(s==='bearish'?'bearish':'neutral');\n    const t=n.pubDate?n.pubDate.slice(0,11):(n.time_published?n.time_published.slice(0,10):'');\n    return`<a class=\"news-item\" href=\"${n.link||n.url||'#'}\" target=\"_blank\" rel=\"noopener\"><span class=\"news-sentiment ${cls}\">${s}</span><span>${n.title||''}</span><span class=\"news-time\">${t}</span></a>`;\n  }).join('');\n}\n\nasync function fetchNews(){\n  if(USE_MOCK){\n    newsCache=[\n      {title:'NVIDIA Announces Next-Gen AI Chip Architecture',sentiment:'Bullish',pubDate:'2026-06-09',link:'https://finance.yahoo.com/news/'},\n      {title:'Microsoft Expands Azure AI Infrastructure Across 5 New Regions',sentiment:'Bullish',pubDate:'2026-06-09',link:'https://finance.yahoo.com/news/'},\n      {title:'CrowdStrike Reports Record AI-Driven Threat Detection in Q2',sentiment:'Bullish',pubDate:'2026-06-08',link:'https://finance.yahoo.com/news/'},\n      {title:'AMD Shares Slip Amid Concerns Over Data Center GPU Competition',sentiment:'Bearish',pubDate:'2026-06-08',link:'https://finance.yahoo.com/news/'},\n      {title:'Palantir Wins $480M U.S. Defense AI Analytics Contract',sentiment:'Bullish',pubDate:'2026-06-07',link:'https://finance.yahoo.com/news/'},\n      {title:'Snowflake Launches Cortex AI — Enterprise Data Platform Expands',sentiment:'Somewhat-Bullish',pubDate:'2026-06-07',link:'https://finance.yahoo.com/news/'},\n    ];renderNews();return;\n  }\n  try{\n    const r=await fetch(NEWS_URL);\n    if(r.ok){\n      const j=await r.json();\n      if(j&&j.items&&j.items.length){newsCache=j.items;renderNews();return;}\n    }\n    renderNews(); // 显示空状态\n  }catch(e){console.warn('News fetch failed',e);renderNews();}\n}\n\nfunction renderTicker(){\n  const strip=document.getElementById('tickerStrip');if(!strip)return;\n  let h='';for(const sec of Object.values(SECTORS))for(const st of sec.stocks){const d=stockData[st.symbol];if(!d||!d.quote)continue;const q=d.quote,cls=q.changePercent>=0?'up':'down',sgn=q.changePercent>=0?'+':'';h+=`<span class=\"ticker-item\"><span class=\"ticker-symbol\">${st.symbol}</span><span class=\"ticker-price\">${q.price.toFixed(2)}</span><span class=\"ticker-change ${cls}\">${sgn}${q.changePercent.toFixed(2)}%</span></span>`;}strip.innerHTML=h;\n}\n\nfunction renderSectors(){\n  for(const[sid,sec]of Object.entries(SECTORS)){\n    const body=document.getElementById(`body-${sid}`);if(!body)continue;\n    let h='',tc=0,cnt=0;\n    for(const st of sec.stocks){const d=stockData[st.symbol];if(!d||!d.quote){h+=cardEmpty(st);continue;}const q=d.quote,cls=q.changePercent>=0?'up':'down',sgn=q.changePercent>=0?'+':'',sel=selectedStock===st.symbol?' selected':'',flowCls=q.changePercent>=0?'inflow':'outflow';tc+=q.changePercent;cnt++;h+=`<div class=\"stock-card${sel}\" onclick=\"selectStock('${st.symbol}')\"><div class=\"stock-symbol\">${st.symbol}</div><div class=\"stock-name\">${st.name}</div><div class=\"stock-price-row\"><span class=\"stock-price\">${q.price.toFixed(2)}</span><span class=\"stock-change ${cls}\">${sgn}${q.changePercent.toFixed(2)}%</span></div><div class=\"stock-vol-row\"><span class=\"stock-vol-num\">Vol ${fmtVol(q.volume)}</span><div class=\"stock-vol-rule\"><div class=\"stock-vol-fill ${flowCls}\" style=\"width:${volPct(st.symbol,sid)}%\"></div></div></div></div>`;}body.innerHTML=h;\n    const avgEl=document.getElementById(`avg-${sid}`);if(avgEl&&cnt){const avg=tc/cnt;avgEl.textContent=`${avg>=0?'+':''}${avg.toFixed(2)}%`;avgEl.className='sector-pct '+(avg>=0?'up':'down');}\n  }\n}\nfunction cardEmpty(st){return`<div class=\"stock-card\" onclick=\"showToast('No data — click Refresh')\"><div class=\"stock-symbol\">${st.symbol}</div><div class=\"stock-name\">${st.name}</div><div class=\"stock-price-row\"><span class=\"stock-price\" style=\"color:var(--ink-faint)\">—</span></div></div>`;}\nfunction volPct(sym,sid){const sec=SECTORS[sid];let mx=0;for(const s of sec.stocks){const d=stockData[s.symbol];if(d&&d.quote&&d.quote.volume>mx)mx=d.quote.volume;}const d=stockData[sym];return mx?Math.max(3,((d?.quote?.volume||0)/mx)*100):5;}\nfunction fmtVol(v){if(!v)return'--';if(v>=1e9)return(v/1e9).toFixed(2)+'B';if(v>=1e6)return(v/1e6).toFixed(1)+'M';if(v>=1e3)return(v/1e3).toFixed(0)+'K';return String(v);}\n\nfunction renderComparison(){\n  const list=document.getElementById('compList');if(!list)return;\n  const ranks=[];for(const[sid,sec]of Object.entries(SECTORS)){let t=0,c=0,u=0,d=0;for(const st of sec.stocks){const dd=stockData[st.symbol];if(dd&&dd.quote){t+=dd.quote.changePercent;c++;dd.quote.changePercent>=0?u++:d++;}}if(c)ranks.push({sid,numeral:sec.numeral,name:sec.name,avg:t/c,up:u,down:d});}\n  ranks.sort((a,b)=>b.avg-a.avg);\n  list.innerHTML=ranks.map((r,i)=>{const cls=r.avg>=0?'up':'down',sgn=r.avg>=0?'+':'';return`<div class=\"rank-item\"><span class=\"rank-num\">${String(i+1).padStart(2,'0')}</span><span class=\"rank-label\">${r.numeral} ${r.name}</span><div class=\"rank-stats\"><div class=\"rank-pct ${cls}\">${sgn}${r.avg.toFixed(2)}%</div><div class=\"rank-tally\"><span class=\"t-up\">${r.up}↑</span> <span class=\"t-down\">${r.down}↓</span></div></div></div>`;}).join('');\n}\n\n// =================== K-line (Light Theme Canvas) ===================\nfunction renderKline(sym){\n  const d=stockData[sym];\n  const placeholder=document.getElementById('klinePlaceholder');\n  const canvas=document.getElementById('klineCanvas');\n  const label=document.getElementById('klineStockLabel');\n  label.textContent=sym;\n\n  // 无 Daily 数据：清空旧图 + 显示加载状态\n  const summary=document.getElementById('klineSummary');\n  if(!d||!d.daily||!d.daily.length){\n    if(summary)summary.style.display='none';\n    canvas.style.display='none';\n    if(placeholder){\n      placeholder.style.display='block';\n      placeholder.innerHTML=`<div class=\"kline-empty\">Loading chart data for <b>${sym}</b> — please wait…</div>`;\n    }\n    // 如果连 quote 都没有，显示等待提示\n    if(!d||!d.quote){\n      if(placeholder)placeholder.innerHTML=`<div class=\"kline-empty\">No data for <b>${sym}</b> — click Refresh to fetch</div>`;\n    }\n    return;\n  }\n\n  placeholder.style.display='none';\n  canvas.style.display='block';\n\n  // OHLCV 摘要条\n  if(summary&&d.quote){\n    const q=d.quote;\n    const latestDaily=d.daily[d.daily.length-1];\n    const openCls=(latestDaily&&latestDaily.close>=latestDaily.open)?'ks-up':'ks-down';\n    summary.style.display='flex';\n    summary.innerHTML=`\n      <span><span class=\"ks-label\">Open</span> ${latestDaily?latestDaily.open.toFixed(2):'—'}</span>\n      <span><span class=\"ks-label\">High</span> ${latestDaily?latestDaily.high.toFixed(2):'—'}</span>\n      <span><span class=\"ks-label\">Low</span> ${latestDaily?latestDaily.low.toFixed(2):'—'}</span>\n      <span class=\"${openCls}\"><span class=\"ks-label\">Close</span> ${latestDaily?latestDaily.close.toFixed(2):'—'}</span>\n      <span class=\"${q.changePercent>=0?'ks-up':'ks-down'}\"><span class=\"ks-label\">Chg</span> ${q.changePercent>=0?'+':''}${q.changePercent.toFixed(2)}%</span>\n      <span><span class=\"ks-label\">Vol</span> ${fmtVol(q.volume)}</span>`;\n  }\n\n  const daily=d.daily.slice(-klineRange);\n  const container=canvas.parentElement;\n  const w=container.clientWidth-40,h=370,dpr=window.devicePixelRatio||1;\n  canvas.width=w*dpr;canvas.height=h*dpr;canvas.style.width=w+'px';canvas.style.height=h+'px';\n  const ctx=canvas.getContext('2d');ctx.scale(dpr,dpr);\n\n  // Paper background\n  ctx.fillStyle='#fdfbf6';ctx.fillRect(0,0,w,h);\n\n  const pad={top:24,right:20,bottom:32,left:66};\n  const cw=w-pad.left-pad.right,ch=h-pad.top-pad.bottom-58;\n  const vTop=ch+pad.top+44,vH=48;\n  const gap=cw/daily.length,candleW=Math.max(1.5,Math.min(10,gap*.65));\n\n  let mn=Infinity,mx=-Infinity,mv=0;\n  daily.forEach(d=>{if(d.low<mn)mn=d.low;if(d.high>mx)mx=d.high;if(d.volume>mv)mv=d.volume;});\n  const pr=mx-mn,pp=pr*.08,yMin=mn-pp,yMax=mx+pp;\n  const toY=p=>pad.top+ch-((p-yMin)/(yMax-yMin))*ch;\n  const toX=i=>pad.left+i*gap+gap/2;\n\n  // Grid — fine ink lines\n  ctx.strokeStyle='#e0dbd0';ctx.lineWidth=0.5;\n  for(let i=0;i<=4;i++){const y=toY(yMin+(yMax-yMin)*(i/4));ctx.beginPath();ctx.moveTo(pad.left,y);ctx.lineTo(w-pad.right,y);ctx.stroke();}\n  ctx.fillStyle='#8a8578';ctx.font='10px \"Chivo Mono\", monospace';\n  for(let i=0;i<=4;i++)ctx.fillText((yMin+(yMax-yMin)*(i/4)).toFixed(2),4,toY(yMin+(yMax-yMin)*(i/4))+4);\n\n  // Dates\n  ctx.fillStyle='#8a8578';ctx.font='9px \"Chivo Mono\", monospace';\n  const step=Math.max(1,Math.floor(daily.length/6));\n  for(let i=0;i<daily.length;i+=step)ctx.fillText(daily[i].date.slice(5),toX(i)-16,h-pad.bottom+14);\n\n  // Volume — subtle ink wash\n  daily.forEach((d,i)=>{const x=toX(i)-candleW/2,bh=(d.volume/mv)*vH,up=d.close>=d.open;ctx.fillStyle=up?'rgba(31,77,61,0.18)':'rgba(139,58,58,0.14)';ctx.fillRect(x,vTop+vH-bh,candleW,bh);});\n\n  // Candles — ink on paper\n  daily.forEach((d,i)=>{\n    const x=toX(i),up=d.close>=d.open;\n    const bh=Math.max(.5,toY(Math.min(d.open,d.close))-toY(Math.max(d.open,d.close)));\n    ctx.strokeStyle=up?'#1f4d3d':'#8b3a3a';ctx.lineWidth=1;\n    ctx.beginPath();ctx.moveTo(x,toY(d.high));ctx.lineTo(x,toY(d.low));ctx.stroke();\n    ctx.fillStyle=up?'#1f4d3d':'#8b3a3a';\n    ctx.fillRect(x-candleW/2,toY(Math.max(d.open,d.close)),candleW,bh);\n  });\n\n  canvas._kd={daily,toX,toY,yMin,yMax,pad,cw,ch,w,h,vTop,vH,candleW,gap,mv};\n}\n\n// =================== Canvas Hover ===================\nconst klineCanvas=document.getElementById('klineCanvas');\nklineCanvas.addEventListener('mousemove',function(e){\n  const kd=this._kd;if(!kd)return;\n  const rect=this.getBoundingClientRect(),mx=e.clientX-rect.left,my=e.clientY-rect.top;\n  let nearest=null,minD=Infinity;\n  kd.daily.forEach((d,i)=>{const cx=kd.toX(i),dist=Math.abs(mx-cx);if(dist<kd.gap&&dist<minD){nearest={...d,index:i,cx};minD=dist;}});\n  renderKline(selectedStock);if(!nearest||minD>=kd.gap)return;\n  const ctx=this.getContext('2d'),dpr=window.devicePixelRatio||1;ctx.save();ctx.setTransform(dpr,0,0,dpr,0,0);\n  // Crosshair — brass rule\n  ctx.strokeStyle='#b8935a';ctx.lineWidth=.5;ctx.setLineDash([3,5]);\n  ctx.beginPath();ctx.moveTo(nearest.cx,kd.pad.top);ctx.lineTo(nearest.cx,kd.vTop+kd.vH);ctx.stroke();ctx.setLineDash([]);\n  // Tooltip — like a slip of paper\n  const tx=nearest.cx>kd.w/2?nearest.cx-138:nearest.cx+10,ty=kd.pad.top+4;\n  ctx.fillStyle='#fdfbf6';ctx.strokeStyle='#c8c2b4';ctx.lineWidth=1;\n  ctx.beginPath();rr(ctx,tx,ty,128,92,2);ctx.fill();ctx.stroke();\n  ctx.fillStyle='#4a4640';ctx.font='10px \"Chivo Mono\", monospace';ctx.fillText(nearest.date,tx+8,ty+18);\n  ctx.fillStyle='#1a1815';ctx.fillText('O '+nearest.open.toFixed(2),tx+8,ty+36);ctx.fillText('H '+nearest.high.toFixed(2),tx+8,ty+52);\n  ctx.fillText('L '+nearest.low.toFixed(2),tx+8,ty+68);ctx.fillText('C '+nearest.close.toFixed(2),tx+8,ty+84);\n  ctx.restore();\n});\nklineCanvas.addEventListener('mouseleave',function(){if(selectedStock)renderKline(selectedStock);});\nfunction rr(c,x,y,w,h,r){c.moveTo(x+r,y);c.lineTo(x+w-r,y);c.quadraticCurveTo(x+w,y,x+w,y+r);c.lineTo(x+w,y+h-r);c.quadraticCurveTo(x+w,y+h,x+w-r,y+h);c.lineTo(x+r,y+h);c.quadraticCurveTo(x,y+h,x,y+h-r);c.lineTo(x,y+r);c.quadraticCurveTo(x,y,x+r,y);c.closePath();}\n\n// =================== Interactions ===================\nasync function selectStock(sym){\n  selectedStock=sym;renderAll();\n  document.getElementById('klineSection').scrollIntoView({behavior:'smooth',block:'nearest'});\n  // 如果缺少 daily 数据（缓存不完整），按需补拉\n  const d=stockData[sym];\n  if(d&&d.quote&&(!d.daily||!d.daily.length)&&!USE_MOCK){\n    showToast('Loading chart data…');\n    const j=await fetchYF(sym);\n    const parsed=parseYF(j);\n    if(parsed&&parsed.daily&&parsed.daily.length){\n      stockData[sym].daily=parsed.daily;\n      saveCache(stockData);\n      renderKline(sym);\n    }\n  }\n}\nfunction setKlineRange(days,btn){klineRange=days;document.querySelectorAll('.kline-rbtn').forEach(b=>b.classList.remove('active'));if(btn)btn.classList.add('active');if(selectedStock)renderKline(selectedStock);}\nfunction toggleSector(sid){document.getElementById(`sector-${sid}`).classList.toggle('folded');}\n\nasync function handleRefresh(){\n  debugLog('▶ Refresh clicked');\n  const btn=document.getElementById('btnRefresh');\n  if(!btn){debugLog('ERROR: btnRefresh not found');return;}\n  if(btn.classList.contains('loading')){debugLog('Already loading, skip');return;}\n  btn.classList.add('loading');\n  try{\n    await fetchAll(true);\n    debugLog('fetchAll returned, stocks='+Object.keys(stockData).length);\n    fetchNews();\n    const hasData = Object.keys(stockData).length > 0;\n    lastRefreshTime = hasData ? new Date() : lastRefreshTime;\n    updateMeta();\n    showToast(hasData ? 'Data refreshed from Yahoo Finance' : 'Refreshed');\n  } catch(e){\n    debugLog('ERROR in refresh: '+e.message);\n    showToast('Refresh failed');\n  } finally {\n    btn.classList.remove('loading');btn.innerHTML='↻ <span>Refresh</span>';\n  }\n}\n\nfunction updateMeta(){\n  const badge=document.getElementById('modeBadge');badge.textContent=USE_MOCK?'mock':'live';badge.className='mode-badge '+(USE_MOCK?'mock':'live');\n  const now=lastRefreshTime||new Date(),ts=now.toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit',second:'2-digit'});\n  document.getElementById('lastUpdate').textContent=ts;\n  const st=document.getElementById('statusMsg');\n  if(st&&!st.textContent.startsWith('Loading')){const n=Object.keys(stockData).length;st.textContent=n?`Loaded ${n} tickers`:'Ready — click Refresh';}\n  document.getElementById('footerTime').textContent='last update: '+now.toLocaleString('zh-CN');\n  document.getElementById('apiCount').textContent=USE_MOCK?'calls: mock (0)':'calls: '+apiCallCount+' today';\n}\n\nfunction showToast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');clearTimeout(t._tid);t._tid=setTimeout(()=>t.classList.remove('show'),2200);}\nfunction sleep(ms){return new Promise(r=>setTimeout(r,ms));}\n\n// =================== Init ===================\nasync function init(){\n  debugLog('init() — USE_MOCK='+USE_MOCK);\n  try{\n    if(USE_MOCK){loadMockData();lastRefreshTime=new Date();fetchNews();debugLog('Mock data loaded');}\n    else{const cached=loadCache();debugLog('Cache '+(cached?'found (age='+Math.round((Date.now()-cached.timestamp)/1000)+'s)':'empty'));if(cached&&(Date.now()-cached.timestamp<CACHE_TTL.quote)){stockData=cached.data;lastRefreshTime=new Date(cached.timestamp);debugLog('Using cached data');}if(!Object.keys(stockData).length){debugLog('Starting fetchAll…');fetchAll().then(()=>{lastRefreshTime=new Date();renderAll();debugLog('fetchAll complete');});}fetchNews();}\n    renderAll();\n  }catch(e){debugLog('ERROR in init: '+e.message);console.error(e);}\n  document.addEventListener('keydown',e=>{if(e.key==='r'&&e.ctrlKey){e.preventDefault();handleRefresh();}});\n}\ninit();\nconsole.log('◆ The Ledger — AI Sector Monitor');\n</script>\n</body>\n</html>\n";

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;
    const symbol = url.searchParams.get('symbol') || '';

    if (path === '/api/stock' && symbol) return proxyStock(symbol);
    if (path === '/api/news') return proxyNews();
    return new Response(HTML, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
  }
};

async function proxyStock(symbol) {
  const resp = await fetch('https://hq.sinajs.cn/list=gb_' + symbol.toLowerCase(), {
    headers: { 'Referer': 'https://finance.sina.com.cn' }
  });
  const text = await resp.text();
  const m = text.match(new RegExp('var hq_str_gb_' + symbol.toLowerCase() + '="([^"]*)"'));
  if (!m) return Response.json({ error: 'no data' }, { status: 502 });
  
  const f = m[1].split(',');
  const price = parseFloat(f[1]) || 0;
  const changePct = parseFloat(f[2]) || 0;
  const volume = parseInt(f[10]) || 0;
  const prevClose = price / (1 + changePct / 100);
  const now = Math.floor(Date.now() / 1000);

  return Response.json({
    chart: { result: [{ meta: {
      symbol, regularMarketPrice: price, chartPreviousClose: prevClose,
      previousClose: prevClose, regularMarketVolume: volume
    }, timestamp: [now],
    indicators: { quote: [{ open: [price], high: [price], low: [price], close: [price], volume: [volume] }] } }] }
  });
}

async function proxyNews() {
  try {
    const r = await fetch('https://feeds.finance.yahoo.com/rss/2.0/headline?s=NVDA,AMD,AVGO,MSFT,AMZN,GOOGL,CRM,PLTR,CRWD,PANW&region=US&lang=en-US', { headers: { 'User-Agent': 'Mozilla/5.0' } });
    const xml = await r.text();
    const items = [];
    const re = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = re.exec(xml)) !== null) {
      const item = m[1];
      const t = (item.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/) || [])[1] || '';
      const l = (item.match(/<link>(.*?)<\/link>/) || [])[1] || '#';
      const d = (item.match(/<pubDate>(.*?)<\/pubDate>/) || [])[1] || '';
      if (t) items.push({ title: t, link: l, pubDate: d.slice(0,11), sentiment: 'neutral' });
    }
    return Response.json({ items: items.slice(0, 15) });
  } catch(e) { return Response.json({ items: [] }); }
}
